// ===========================================
// W1 Step 1: Deferred Quest Migration
// ===========================================
// Fetches today's quests with state "To-Do" and target_date before today,
// moves them to "Deferred" state, increments defer_count.

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  states: {
    todo: $env.PULSE_STATE_TODO_ID,
    in_progress: $env.PULSE_STATE_IN_PROGRESS_ID,
    deferred: $env.PULSE_STATE_DEFERRED_ID,
    done: $env.PULSE_STATE_DONE_ID,
    canceled: $env.PULSE_STATE_CANCELED_ID,
  },
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

// Get today's date in KST
const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: tz }); // YYYY-MM-DD

// --- Retry helper ---
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;

const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) throw e;
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPatch = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'PATCH', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

// --- Step 1 Logic ---
const w1StartTime = new Date().toISOString();
const projectId = config.daily_quest_project_id;
let itemsProcessed = 0;
let itemsFailed = 0;
const deferredIssues = [];
const existingSourceIds = new Set();

try {
  // Fetch all issues in Daily Quests project with state To-Do
  const todoIssues = await withRetry(
    () => apiGet(`/projects/${projectId}/issues/?per_page=100&expand=labels,state&state=${config.states.todo}`),
    'Fetch To-Do issues'
  );

  const issues = todoIssues.results || todoIssues || [];

  // Also fetch today's existing quests for duplicate prevention data (passed to Step 2)
  const todayIssues = await withRetry(
    () => apiGet(`/projects/${projectId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today issues'
  );
  const todayResults = todayIssues.results || todayIssues || [];
  for (const issue of todayResults) {
    // Extract source_issue_id from description pulse-meta if available
    const metaMatch = (issue.description_html || '').match(/"source_issue_id"\s*:\s*"([^"]+)"/);
    if (metaMatch) existingSourceIds.add(metaMatch[1]);
  }

  // Filter: only issues with target_date before today
  const overdueIssues = issues.filter((issue) => {
    const targetDate = issue.target_date;
    return targetDate && targetDate < todayStr;
  });

  // Process each overdue issue
  for (const issue of overdueIssues) {
    try {
      // Extract current defer_count from description or default to 0
      let deferCount = 0;
      const countMatch = (issue.description_html || '').match(/"defer_count"\s*:\s*(\d+)/);
      if (countMatch) deferCount = parseInt(countMatch[1], 10);
      deferCount += 1;

      // Update defer_count in description_html pulse-meta
      const updateDescriptionWithDeferCount = (html, newCount) => {
        if (!html) return html;
        // Try to update existing defer_count in pulse-meta JSON
        const updated = html.replace(/("defer_count"\s*:\s*)\d+/, `$1${newCount}`);
        if (updated !== html) return updated;
        // If defer_count field doesn't exist, add it before the closing brace of pulse-meta JSON
        // Match the last } in code block content and insert defer_count before it
        return html.replace(/(<pre><code[^>]*>[\s\S]*?)(\}\s*<\/code><\/pre>)/, `$1,\n  "defer_count": ${newCount}\n$2`);
      };

      if (isDryRun) {
        console.log(`[DRY_RUN] Would defer issue: "${issue.name}" (defer_count: ${deferCount})`);
      } else {
        // Update description_html with new defer_count
        const updatedDescription = updateDescriptionWithDeferCount(issue.description_html, deferCount);

        // Move to Deferred state + persist defer_count in description
        const patchBody = { state: config.states.deferred };
        if (updatedDescription && updatedDescription !== issue.description_html) {
          patchBody.description_html = updatedDescription;
        }
        await withRetry(
          () => apiPatch(`/projects/${projectId}/issues/${issue.id}/`, patchBody),
          `Defer issue ${issue.id}`
        );

        // Add comment
        const comment = `\u23F3 [00:00] Auto-deferred: incomplete (count: ${deferCount})`;
        await withRetry(
          () => apiPost(`/projects/${projectId}/issues/${issue.id}/comments/`, { comment_html: `<p>${comment}</p>` }),
          `Comment on ${issue.id}`
        );
      }

      deferredIssues.push({ id: issue.id, name: issue.name, defer_count: deferCount });
      itemsProcessed++;
    } catch (e) {
      console.log(`[ERROR] Failed to defer issue "${issue.name}": ${e.message}`);
      itemsFailed++;
    }
  }

  return [{
    json: {
      success: true,
      data: {
        deferred_issues: deferredIssues,
        existing_source_ids: Array.from(existingSourceIds),
        today_date: todayStr,
        w1_start_time: w1StartTime,
      },
      error: null,
      metadata: {
        step: 'step_1_deferred_migration',
        timestamp: new Date().toISOString(),
        items_processed: itemsProcessed,
        items_failed: itemsFailed,
        dry_run: isDryRun,
      }
    }
  }];
} catch (e) {
  return [{
    json: {
      success: false,
      data: {
        deferred_issues: deferredIssues,
        existing_source_ids: Array.from(existingSourceIds),
        today_date: todayStr,
        w1_start_time: w1StartTime,
      },
      error: { code: 'PLANE_API_ERROR', message: e.message },
      metadata: {
        step: 'step_1_deferred_migration',
        timestamp: new Date().toISOString(),
        items_processed: itemsProcessed,
        items_failed: itemsFailed,
        dry_run: isDryRun,
      }
    }
  }];
}

// ===========================================
// W1 Step 2: Deterministic Routine Copy
// ===========================================
// Scans all projects for issues with 'daily-routine' label,
// evaluates schedule conditions, creates qualifying quests.

const step1 = $input.first().json;
const step1Data = step1.data || {};
const existingSourceIds = new Set(step1Data.existing_source_ids || []);
const todayStr = step1Data.today_date;

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  states: {
    todo: $env.PULSE_STATE_TODO_ID,
  },
  label_daily_routine: $env.PULSE_LABEL_DAILY_ROUTINE_ID,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

// Day-of-week mapping for KST
const dayNames = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
const nowDate = new Date();
const kstDay = dayNames[new Date(nowDate.toLocaleString('en-US', { timeZone: tz })).getDay()];

// --- Retry helper ---
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) throw e;
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

// --- pulse-meta parser (inline for n8n Code node) ---
const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'");

const extractMeta = (html) => {
  if (!html) return null;
  let m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
  if (m) return m[1].trim();
  m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
  if (m) return decodeEntities(m[1].trim());
  m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
  if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return c; }
  return null;
};

// --- Priority mapping (Plane.so priority enum) ---
const priorityMap = { urgent: 4, high: 3, medium: 2, low: 1, none: 0 };
const validRoutineTypes = ['daily', 'weekly', 'custom'];
const validPriorities = ['urgent', 'high', 'medium', 'low'];

// --- Main Logic ---
let itemsProcessed = 0;
let itemsFailed = 0;
const createdQuests = [];
const warnings = [];

try {
  // Fetch recent quests for cooldown check (last 30 days)
  const cooldownLookbackDays = 30;
  const lookbackDate = new Date(nowDate);
  lookbackDate.setDate(lookbackDate.getDate() - cooldownLookbackDays);
  const lookbackStr = lookbackDate.toLocaleDateString('en-CA', { timeZone: tz });
  const recentRes = await withRetry(
    () => apiGet(`/projects/${config.daily_quest_project_id}/issues/?per_page=100&expand=labels,state`),
    'Fetch recent quests for cooldown'
  );
  const recentIssues = recentRes.results || recentRes || [];
  // Build map: source_issue_id -> most recent target_date
  const lastQuestDateBySource = new Map();
  for (const ri of recentIssues) {
    if (!ri.target_date || ri.target_date < lookbackStr) continue;
    const srcMatch = (ri.description_html || '').match(/"source_issue_id"\s*:\s*"([^"]+)"/);
    if (srcMatch) {
      const existing = lastQuestDateBySource.get(srcMatch[1]);
      if (!existing || ri.target_date > existing) {
        lastQuestDateBySource.set(srcMatch[1], ri.target_date);
      }
    }
  }

  // Get all projects
  const projectsRes = await withRetry(() => apiGet('/projects/'), 'List projects');
  const projects = projectsRes.results || projectsRes || [];

  let totalRoutinesScanned = 0;

  for (const project of projects) {
    // Skip the daily quest project itself
    if (project.id === config.daily_quest_project_id) continue;

    // Fetch issues with labels expanded
    const issuesRes = await withRetry(
      () => apiGet(`/projects/${project.id}/issues/?per_page=100&expand=labels,state`),
      `Fetch issues for ${project.identifier}`
    );
    const issues = issuesRes.results || issuesRes || [];

    for (const issue of issues) {
      if (totalRoutinesScanned >= 100) break;

      // Check labels for daily-routine
      const labels = issue.label_detail || issue.labels || [];
      const labelNames = labels.map((l) => (typeof l === 'string' ? l : l.name || ''));

      const hasExactLabel = labelNames.includes('daily-routine');
      const hasNearMatch = !hasExactLabel && labelNames.some((n) =>
        n.toLowerCase().includes('daily') && n.toLowerCase().includes('routine')
      );

      if (hasNearMatch) {
        const nearLabel = labelNames.find((n) => n.toLowerCase().includes('daily') && n.toLowerCase().includes('routine'));
        warnings.push(`\u26A0\uFE0F [LABEL_MISMATCH] Issue '${issue.name}' has label '${nearLabel}' \u2014 did you mean 'daily-routine'?`);
        console.log(warnings[warnings.length - 1]);
      }

      if (!hasExactLabel) continue;
      totalRoutinesScanned++;

      // Parse pulse-meta
      const raw = extractMeta(issue.description_html);
      if (!raw) {
        warnings.push(`\u26A0\uFE0F [INVALID_ROUTINE_META] Routine '${issue.name}' has no pulse-meta block \u2014 skipped`);
        console.log(warnings[warnings.length - 1]);
        continue;
      }

      let meta;
      try { meta = JSON.parse(raw); } catch (e) {
        warnings.push(`\u26A0\uFE0F [INVALID_ROUTINE_META] Routine '${issue.name}' has invalid JSON \u2014 skipped`);
        console.log(warnings[warnings.length - 1]);
        continue;
      }

      // Validate required fields and types
      const metaErrors = [];
      if (meta.schema_version !== 1) metaErrors.push('invalid schema_version');
      if (!meta.routine_days || !Array.isArray(meta.routine_days) || meta.routine_days.length === 0) metaErrors.push('missing/invalid routine_days');
      if (!meta.routine_time) metaErrors.push('missing routine_time');
      if (!meta.source_issue_id) metaErrors.push('missing source_issue_id');
      if (meta.routine_type && !validRoutineTypes.includes(meta.routine_type)) metaErrors.push(`invalid routine_type: ${meta.routine_type}`);
      if (meta.routine_priority && !validPriorities.includes(meta.routine_priority)) metaErrors.push(`invalid routine_priority: ${meta.routine_priority}`);
      if (metaErrors.length > 0) {
        warnings.push(`\u26A0\uFE0F [INVALID_ROUTINE_META] Routine '${issue.name}' validation failed: ${metaErrors.join(', ')} \u2014 skipped`);
        console.log(warnings[warnings.length - 1]);
        continue;
      }

      // --- Schedule evaluation ---
      // Check routine_days
      if (!meta.routine_days.includes(kstDay)) continue;

      // Check active_from
      if (meta.routine_active_from && meta.routine_active_from > todayStr) continue;

      // Check active_until
      if (meta.routine_active_until && meta.routine_active_until < todayStr) continue;

      // Check cooldown_days
      if (meta.routine_cooldown_days && meta.routine_cooldown_days > 0) {
        const lastDate = lastQuestDateBySource.get(meta.source_issue_id);
        if (lastDate) {
          const lastMs = new Date(lastDate + 'T00:00:00').getTime();
          const todayMs = new Date(todayStr + 'T00:00:00').getTime();
          const daysSince = Math.floor((todayMs - lastMs) / (24 * 60 * 60 * 1000));
          if (daysSince < meta.routine_cooldown_days) {
            console.log(`[SKIP] Cooldown: source ${meta.source_issue_id} last created ${lastDate}, cooldown ${meta.routine_cooldown_days}d, only ${daysSince}d ago`);
            continue;
          }
        }
      }

      // Duplicate prevention
      if (existingSourceIds.has(meta.source_issue_id)) {
        console.log(`[SKIP] Duplicate: quest already exists for source ${meta.source_issue_id}`);
        continue;
      }

      // --- Create quest ---
      const questName = issue.name;
      const questPriority = priorityMap[meta.routine_priority] ?? 2;
      const questDescription = `<pre><code class="language-pulse-meta">${JSON.stringify({
        schema_version: 1,
        routine_type: meta.routine_type || 'daily',
        routine_days: meta.routine_days,
        source_project_id: project.id,
        source_issue_id: issue.id,
        routine_time: meta.routine_time,
        routine_duration_min: meta.routine_duration_min,
        routine_priority: meta.routine_priority,
        routine_mandatory: meta.routine_mandatory || false,
        routine_active_from: meta.routine_active_from || todayStr,
        routine_cooldown_days: meta.routine_cooldown_days || 0,
        defer_count: 0,
      }, null, 2)}</code></pre>`;

      if (isDryRun) {
        console.log(`[DRY_RUN] Would create quest: "${questName}" at ${meta.routine_time}`);
        createdQuests.push({ name: questName, time: meta.routine_time, source_issue_id: issue.id, dry_run: true });
        itemsProcessed++;
      } else {
        try {
          const created = await withRetry(
            () => apiPost(`/projects/${config.daily_quest_project_id}/issues/`, {
              name: questName,
              description_html: questDescription,
              state: config.states.todo,
              priority: questPriority,
              target_date: todayStr,
            }),
            `Create quest for ${issue.id}`
          );

          // Add source comment
          await withRetry(
            () => apiPost(`/projects/${config.daily_quest_project_id}/issues/${created.id}/comments/`, {
              comment_html: `<p>\uD83D\uDD04 [00:00] Auto-generated from routine: ${questName} (project: ${project.name})</p>`
            }),
            `Comment on quest ${created.id}`
          );

          createdQuests.push({ id: created.id, name: questName, time: meta.routine_time, source_issue_id: issue.id });
          existingSourceIds.add(meta.source_issue_id);
          itemsProcessed++;
        } catch (e) {
          console.log(`[ERROR] Failed to create quest for "${questName}": ${e.message}`);
          itemsFailed++;
        }
      }
    }
    if (totalRoutinesScanned >= 100) break;
  }

  return [{
    json: {
      success: true,
      data: {
        step_1: step1Data,
        step_1_metadata: step1.metadata || {},
        created_quests: createdQuests,
        warnings,
        today_date: todayStr,
      },
      error: null,
      metadata: {
        step: 'step_2_routine_copy',
        timestamp: new Date().toISOString(),
        items_processed: itemsProcessed,
        items_failed: itemsFailed,
        dry_run: isDryRun,
      }
    }
  }];
} catch (e) {
  return [{
    json: {
      success: false,
      data: {
        step_1: step1Data,
        step_1_metadata: step1.metadata || {},
        created_quests: createdQuests,
        warnings,
        today_date: todayStr,
      },
      error: { code: 'PLANE_API_ERROR', message: e.message },
      metadata: {
        step: 'step_2_routine_copy',
        timestamp: new Date().toISOString(),
        items_processed: itemsProcessed,
        items_failed: itemsFailed,
        dry_run: isDryRun,
      }
    }
  }];
}

// ===========================================
// W1 Execution Summary & Degraded Mode Check
// ===========================================
// Aggregates results from Steps 1-3, sets DEGRADED_MODE flag
// if any LLM steps were skipped, builds execution summary.

const prevResult = $input.first().json;
const prevData = prevResult.data || {};
const step1Data = prevData.step_1 || {};
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

// Use actual W1 start time from Step 1
const startTime = step1Data.w1_start_time ? new Date(step1Data.w1_start_time) : new Date();
const endTime = new Date();
const totalExecutionMs = endTime.getTime() - startTime.getTime();
const totalExecutionSec = Math.round(totalExecutionMs / 1000);

// Determine which steps completed vs skipped
const stepsCompleted = ['step_1_deferred_migration', 'step_2_routine_copy'];
const stepsSkipped = [];

// Step 3 status
const step3Skipped = prevData.step_3_skipped !== false;
if (!step3Skipped) { stepsCompleted.push('step_3_llm_task_generation'); } else { stepsSkipped.push('step_3_llm_task_generation'); }

// Steps 4-5 not yet implemented
stepsSkipped.push('step_4_llm_schedule_optimization', 'step_5_llm_deferred_restoration');

// Degraded mode if any LLM step was skipped
const degradedMode = stepsSkipped.length > 0;

// Build execution summary
const deferredCount = (step1Data.deferred_issues || []).length;
const createdCount = (prevData.created_quests || []).length;
const aiSuggestedCount = (prevData.step_3_suggestions || []).length;
const warnings = prevData.warnings || [];
const step1Meta = prevData.step_1_metadata || {};
const step3Meta = prevResult.metadata || {};
const step1Errors = step1Meta.items_failed || 0;
const totalErrors = step1Errors + (step3Meta.items_failed || 0);

const summary = {
  today_date: prevData.today_date,
  start_time: startTime.toISOString(),
  end_time: endTime.toISOString(),
  total_execution_time_sec: totalExecutionSec,
  steps_completed: stepsCompleted,
  steps_skipped: stepsSkipped,
  deferred_count: deferredCount,
  quests_created: createdCount,
  ai_suggested: aiSuggestedCount,
  warnings_count: warnings.length,
  errors_count: totalErrors,
  degraded_mode: degradedMode,
  dry_run: isDryRun,
};

// Build notification message
let notification = '';
if (degradedMode) {
  notification = `\u26A0\uFE0F [DEGRADED_MODE] AI features temporarily unavailable. Routine-based quests generated normally.\n`;
}
notification += `\uD83D\uDCCB W1 Execution Summary — ${step2Data.today_date}:\n`;
notification += `  Deferred: ${deferredCount} quests moved to Deferred\n`;
notification += `  Created: ${createdCount} new quests\n`;
if (aiSuggestedCount > 0) {
  notification += `  AI Suggested: ${aiSuggestedCount} task(s)\n`;
}
notification += `  Steps: ${stepsCompleted.length} completed, ${stepsSkipped.length} skipped\n`;
if (warnings.length > 0) {
  notification += `  Warnings: ${warnings.length}\n`;
}
if (totalErrors > 0) {
  notification += `  Errors: ${totalErrors}\n`;
}
notification += `  Duration: ${totalExecutionSec}s\n`;

// Persist execution status to Daily Quest project description for W2 /today
const projectId = $env.PULSE_DAILY_QUEST_PROJECT_ID;
const basePath = `${$env.PULSE_PLANE_BASE_URL}/api/v1/workspaces/${$env.PULSE_PLANE_WORKSPACE_SLUG}`;
const headers = { 'X-API-Key': $env.PULSE_PLANE_API_KEY, 'Content-Type': 'application/json' };
const todayStr = prevData.today_date;
const statusMeta = JSON.stringify({ last_run: todayStr, degraded_mode: degradedMode, total_execution_time_sec: totalExecutionSec });
const statusHtml = `<pre><code class="language-pulse-status">${statusMeta}</code></pre>`;
try {
  if (!isDryRun) {
    await fetch(`${basePath}/projects/${projectId}/`, { method: 'PATCH', headers, body: JSON.stringify({ description_html: statusHtml }) });
  } else {
    console.log(`[DRY_RUN] Would update project description with status: ${statusMeta}`);
  }
} catch (e) {
  console.log(`[WARN] Failed to persist execution status: ${e.message}`);
}

return [{
  json: {
    success: true,
    data: {
      summary,
      notification,
      degraded_mode: degradedMode,
    },
    error: null,
    metadata: {
      step: 'w1_execution_summary',
      timestamp: new Date().toISOString(),
      items_processed: deferredCount + createdCount,
      items_failed: totalErrors,
    }
  }
}];

// Check DRY_RUN before sending LobeHub notification
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';
const data = $input.first().json.data;

if (isDryRun) {
  console.log(`[DRY_RUN] Would send W1 summary to LobeHub:\n${data.notification}`);
  return [{
    json: {
      dry_run: true,
      message: `[DRY_RUN] Would send W1 execution summary`,
      notification: data.notification,
      should_notify: false,
    }
  }];
}

return [{
  json: {
    should_notify: true,
    notification: data.notification,
    degraded_mode: data.degraded_mode,
  }
}];

// DRY_RUN: log notification skip
const data = $input.first().json;
console.log(data.message);
return [$input.first()];

// ===========================================
// W1 Step 3: LLM Task Generation
// ===========================================
// Sends today's quest list and recent history to DeepSeek.
// Returns 0-3 AI-suggested tasks. Follows P-3 branching pattern.

const step2Result = $input.first().json;
const step2Data = step2Result.data || {};
const step1Data = step2Data.step_1 || {};
const todayStr = step2Data.today_date;
const createdQuests = step2Data.created_quests || [];
const deferredIssues = step1Data.deferred_issues || [];

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  states: { todo: $env.PULSE_STATE_TODO_ID },
};

const dsConfig = {
  api_key: $env.PULSE_DEEPSEEK_API_KEY,
  base_url: $env.PULSE_DEEPSEEK_BASE_URL || 'https://api.deepseek.com/v1',
  model: $env.PULSE_DEEPSEEK_MODEL || 'deepseek-chat',
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const isDryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || '0') === '1';

// --- Retry helpers ---
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const BACKOFF = [1000, 2000, 4000];

const withBackoff = async (fn, ctx) => {
  for (let i = 0; i < 3; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] DeepSeek ${ctx} attempt ${i + 1}/3: ${e.message}`);
      if (i === 2) throw e;
      await sleep(BACKOFF[i]);
    }
  }
};

const PER_STEP_TIMEOUT = 60000;

const callDeepSeek = async (systemPrompt, userPrompt, temperature = 0.7) => {
  const controller = new AbortController();
  const tid = setTimeout(() => controller.abort(), PER_STEP_TIMEOUT);
  try {
    const res = await fetch(`${dsConfig.base_url}/chat/completions`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${dsConfig.api_key}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: dsConfig.model,
        messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }],
        temperature,
        max_tokens: 2048,
        response_format: { type: 'json_object' },
      }),
      signal: controller.signal,
    });
    if (!res.ok) { const t = await res.text().catch(() => ''); throw new Error(`HTTP ${res.status}: ${t}`); }
    const r = await res.json();
    return { content: r.choices?.[0]?.message?.content, usage: r.usage || {} };
  } finally { clearTimeout(tid); }
};

// --- Plane.so helpers ---
const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};
const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

// --- Prompt template ---
const SYSTEM_PROMPT = `You are a personal productivity assistant that suggests additional tasks based on the user's current daily quest list, recent completion history, and project context.

Analyze the user's current quests for today and their recent activity. Suggest 0-3 additional tasks that would complement their schedule. Only suggest tasks when genuinely useful — returning zero suggestions is perfectly valid.

Constraints:
- Return 0 to 3 task suggestions maximum.
- Each suggestion must include: name (string), routine_time (HH:MM format), duration_min (integer, 1-480), priority (one of: urgent, high, medium, low), and rationale (string, 1-2 sentences).
- Suggested routine_time should fit into gaps in the user's existing schedule.
- Do NOT suggest tasks that duplicate or overlap with existing quests.
- Consider the user's recent completion patterns.
- All output must be in English.

You MUST respond with valid JSON: { "suggestions": [...] }
If no suggestions, return: { "suggestions": [] }`;

// --- Validation ---
const VALID_PRIORITIES = ['urgent', 'high', 'medium', 'low'];
const priorityMap = { urgent: 4, high: 3, medium: 2, low: 1 };

const validateResponse = (parsed) => {
  if (!parsed || !Array.isArray(parsed.suggestions)) return 'Missing suggestions array';
  if (parsed.suggestions.length > 3) return 'Too many suggestions (max 3)';
  for (const s of parsed.suggestions) {
    if (!s.name || typeof s.name !== 'string') return 'Invalid suggestion name';
    if (!s.duration_min || typeof s.duration_min !== 'number' || s.duration_min < 1 || s.duration_min > 480) return `Invalid duration_min: ${s.duration_min}`;
    if (!VALID_PRIORITIES.includes(s.priority)) return `Invalid priority: ${s.priority}`;
  }
  return null;
};

// --- Main Logic ---
const startTime = Date.now();
const aiCreatedQuests = [];
let llmUsage = {};
let llmDurationMs = 0;

try {
  // Check if DeepSeek is configured
  if (!dsConfig.api_key) {
    console.log('[SKIP] Step 3: PULSE_DEEPSEEK_API_KEY not configured');
    return [{ json: {
      success: true,
      data: { ...step2Data, step_3_suggestions: [], step_3_skipped: true, step_3_reason: 'DEEPSEEK_NOT_CONFIGURED' },
      error: null,
      metadata: { step: 'step_3_llm_task_generation', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: 0, llm_usage: {}, skipped: true }
    }}];
  }

  // Build user prompt with context
  const questSummary = createdQuests.map(q => `- ${q.name} at ${q.time || 'unscheduled'}`).join('\n') || '(no quests created today)';
  const deferredSummary = deferredIssues.map(d => `- ${d.name} (deferred x${d.defer_count})`).join('\n') || '(none)';

  // Fetch recent completed quests for history context
  let recentHistory = '(unavailable)';
  try {
    const recentRes = await apiGet(`/projects/${config.daily_quest_project_id}/issues/?per_page=20&expand=labels,state&state=${$env.PULSE_STATE_DONE_ID}`);
    const recentDone = (recentRes.results || recentRes || []).slice(0, 10);
    if (recentDone.length > 0) {
      recentHistory = recentDone.map(i => `- ${i.name} (completed: ${i.completed_at || i.target_date || 'unknown'})`).join('\n');
    }
  } catch (e) {
    console.log(`[WARN] Could not fetch recent history: ${e.message}`);
  }

  const userPrompt = `Today: ${todayStr}\n\nToday's Quests:\n${questSummary}\n\nRecently Deferred:\n${deferredSummary}\n\nRecent Completions:\n${recentHistory}`;

  // Call DeepSeek with P-3 pattern
  let result;
  try {
    result = await withBackoff(() => callDeepSeek(SYSTEM_PROMPT, userPrompt, 0.7), 'Step 3');
  } catch (e) {
    const code = e.name === 'AbortError' || e.message?.includes('timeout') ? 'DEEPSEEK_TIMEOUT' : 'DEEPSEEK_API_ERROR';
    console.log(`[ERROR] Step 3 DeepSeek call failed: ${e.message}`);
    return [{ json: {
      success: true,
      data: { ...step2Data, step_3_suggestions: [], step_3_skipped: true, step_3_reason: code },
      error: { code, message: e.message },
      metadata: { step: 'step_3_llm_task_generation', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: {}, skipped: true }
    }}];
  }

  llmUsage = result.usage;

  // Parse and validate JSON
  let parsed;
  try {
    parsed = JSON.parse(result.content);
    const err = validateResponse(parsed);
    if (err) throw new Error(err);
  } catch (parseErr) {
    console.log(`[WARN] Step 3 JSON validation failed: ${parseErr.message}. Retrying with temperature: 0.1`);
    try {
      result = await callDeepSeek(SYSTEM_PROMPT, userPrompt, 0.1);
      llmUsage = result.usage;
      parsed = JSON.parse(result.content);
      const err = validateResponse(parsed);
      if (err) throw new Error(err);
    } catch (retryErr) {
      console.log(`[ERROR] Step 3 second validation failed: ${retryErr.message}`);
      return [{ json: {
        success: true,
        data: { ...step2Data, step_3_suggestions: [], step_3_skipped: true, step_3_reason: 'DEEPSEEK_JSON_PARSE_ERROR' },
        error: { code: 'DEEPSEEK_JSON_PARSE_ERROR', message: retryErr.message },
        metadata: { step: 'step_3_llm_task_generation', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: llmUsage, skipped: true }
      }}];
    }
  }

  llmDurationMs = Date.now() - startTime;
  const suggestions = parsed.suggestions || [];
  console.log(`[INFO] Step 3: DeepSeek returned ${suggestions.length} suggestion(s) in ${llmDurationMs}ms`);

  // Create AI-suggested quests in Plane.so
  for (const suggestion of suggestions) {
    const questDescription = `<pre><code class="language-pulse-meta">${JSON.stringify({
      schema_version: 1,
      routine_type: 'ai-suggested',
      routine_days: [],
      source_project_id: 'ai',
      source_issue_id: `ai-step3-${Date.now()}`,
      routine_time: suggestion.routine_time || '09:00',
      routine_duration_min: suggestion.duration_min,
      routine_priority: suggestion.priority,
      routine_mandatory: false,
      routine_active_from: todayStr,
      routine_cooldown_days: 0,
      defer_count: 0,
    }, null, 2)}</code></pre>`;

    if (isDryRun) {
      console.log(`[DRY_RUN] Would create AI quest: "${suggestion.name}" at ${suggestion.routine_time || '09:00'}`);
      aiCreatedQuests.push({ name: suggestion.name, time: suggestion.routine_time, priority: suggestion.priority, rationale: suggestion.rationale, dry_run: true });
    } else {
      try {
        const created = await apiPost(`/projects/${config.daily_quest_project_id}/issues/`, {
          name: suggestion.name,
          description_html: questDescription,
          state: config.states.todo,
          priority: priorityMap[suggestion.priority] ?? 2,
          target_date: todayStr,
        });
        // Add AI source comment
        const now = new Date();
        const timeStr = now.toLocaleTimeString('en-GB', { timeZone: $env.PULSE_USER_TIMEZONE || 'Asia/Seoul', hour: '2-digit', minute: '2-digit' });
        await apiPost(`/projects/${config.daily_quest_project_id}/issues/${created.id}/comments/`, {
          comment_html: `<p>\uD83E\uDD16 [${timeStr}] AI-suggested task (source: W1 Step 3). Rationale: ${suggestion.rationale || 'N/A'}</p>`
        });
        aiCreatedQuests.push({ id: created.id, name: suggestion.name, time: suggestion.routine_time, priority: suggestion.priority, rationale: suggestion.rationale });
      } catch (e) {
        console.log(`[ERROR] Failed to create AI quest "${suggestion.name}": ${e.message}`);
      }
    }
  }

  return [{ json: {
    success: true,
    data: {
      ...step2Data,
      step_3_suggestions: aiCreatedQuests,
      step_3_skipped: false,
    },
    error: null,
    metadata: {
      step: 'step_3_llm_task_generation',
      timestamp: new Date().toISOString(),
      items_processed: aiCreatedQuests.length,
      items_failed: suggestions.length - aiCreatedQuests.length,
      dry_run: isDryRun,
      llm_duration_ms: llmDurationMs,
      llm_usage: llmUsage,
      skipped: false,
    }
  }}];
} catch (e) {
  console.log(`[ERROR] Step 3 unexpected error: ${e.message}`);
  return [{ json: {
    success: true,
    data: { ...step2Data, step_3_suggestions: aiCreatedQuests, step_3_skipped: true, step_3_reason: 'UNEXPECTED_ERROR' },
    error: { code: 'DEEPSEEK_API_ERROR', message: e.message },
    metadata: { step: 'step_3_llm_task_generation', timestamp: new Date().toISOString(), items_processed: 0, items_failed: 0, dry_run: isDryRun, llm_duration_ms: Date.now() - startTime, llm_usage: llmUsage, skipped: true }
  }}];
}
